int compress_buffer(char *buf, size_t len)
{
	int i;
	int out = 0;

	/* loop through each byte, check if it matches previous byte,
	 * if yes increment run-length counter, otherwise write
	 * length and value pair to output */
	for (i = 0; i < len; i++) {
		out += encode_rle(buf, i, &buf[out]);
	}
	return out;
}
